INSERT INTO `symptom_reports` (`id`, `user_id`, `symptoms`, `score`, `probable_disease`, `severity`, `advice`, `medications`, `created_at`) VALUES
(1, 2, '[\"fatigue\",\"headache\"]', 3, 'Migraine de tension', 'Moyen', 'Reposez-vous dans un endroit calme et bien ventilé. Surveillez votre température et votre hydratation.', '[\"Vitamines\"]', '2026-05-15 17:25:02'),
(2, 3, '[\"fever\",\"headache\"]', 3, 'Infection virale', 'Moyen', 'Détendez-vous, hydratez-vous et ne prenez pas d’antibiotiques sans avis médical. Surveillez votre température et votre hydratation.', '[\"Paracétamol\"]', '2026-05-15 21:25:54'),
(3, 8, 'Fatigue', 35, 'Fatigue générale / Anémie possible', 'Léger', 'Repos, alimentation équilibrée, fer et vitamines.', 'Vitamine C 1000mg, Fer (sur prescription)', '2026-05-18 11:43:53'),
(4, 8, 'Fièvre', 65, 'Fièvre / Paludisme possible', 'Modéré', 'Repos, hydratation, paracétamol. Consultez un médecin si la fièvre dépasse 38.5°C.', 'Paracétamol 500mg, Chloroquine (si paludisme confirmé)', '2026-05-18 12:10:16'),
(5, 8, 'Tension artérielle', 95, 'Hypertension / Problème cardiaque possible', 'Élevé', 'Réduisez le sel, le stress et l\'alcool. Faites mesurer votre tension régulièrement. Consultez un médecin pour un suivi. Ne jamais arrêter un traitement sans avis médical.', 'Traitement sur prescription uniquement, Réduction du sel alimentaire', '2026-05-19 10:11:52'),
(6, 8, 'Tension artérielle', 95, 'Hypertension / Problème cardiaque possible', 'Élevé', 'Réduisez le sel, le stress et l\'alcool. Faites mesurer votre tension régulièrement. Consultez un médecin pour un suivi. Ne jamais arrêter un traitement sans avis médical.', 'Traitement sur prescription uniquement, Réduction du sel alimentaire', '2026-05-19 10:30:46'),
(7, 8, 'Démangeaisons peau', 95, 'Problème dermatologique', 'Léger', 'Évitez de gratter. Gardez la zone propre et sèche. Évitez les produits irritants. Si éruption généralisée ou fièvre associée, consultez un médecin.', 'Crème antihistaminique, Lotion à la calamine, Antihistaminique oral (Cétirizine)', '2026-05-19 10:32:58'),
(8, 8, 'Douleur dos', 95, 'Lombalgie / Douleur dorsale', 'Léger', 'Repos relatif (évitez l\'alitement total). Appliquez de la chaleur locale. Évitez les mouvements brusques. Consultez si douleur irradie dans la jambe ou si perte de sensibilité.', 'Ibuprofène 400mg, Paracétamol 500mg, Gel anti-inflammatoire local', '2026-05-19 10:40:41'),
(9, 8, 'Dama feebar', 95, 'Paludisme / Fièvre', 'Élevé', 'Le paludisme est fréquent au Sénégal. Consultez un médecin rapidement pour un test de goutte épaisse. En attendant : repos, hydratation abondante, paracétamol pour la fièvre.', 'Paracétamol 500mg (fièvre), Chloroquine ou Artémisinine (sur prescription), Sels de réhydratation orale', '2026-05-19 11:14:03'),
(10, 10, 'Insomnie', 95, 'Stress / Anxiété', 'Léger', 'Pratiquez la respiration profonde et la méditation. Réduisez la caféine. Maintenez un rythme de sommeil régulier. Parlez à un proche ou un professionnel si persistant.', 'Tisanes relaxantes (valériane, camomille), Magnésium, Mélatonine (pour le sommeil)', '2026-06-01 13:23:18'),
(11, 10, 'Tension artérielle', 95, 'Hypertension / Problème cardiaque possible', 'Élevé', 'Réduisez le sel, le stress et l\'alcool. Faites mesurer votre tension régulièrement. Consultez un médecin pour un suivi. Ne jamais arrêter un traitement sans avis médical.', 'Traitement sur prescription uniquement, Réduction du sel alimentaire', '2026-06-01 13:38:25'),
(12, 11, 'Dama feebar', 95, 'Paludisme / Fièvre', 'Élevé', 'Le paludisme est fréquent au Sénégal. Consultez un médecin rapidement pour un test de goutte épaisse. En attendant : repos, hydratation abondante, paracétamol pour la fièvre.', 'Paracétamol 500mg (fièvre), Chloroquine ou Artémisinine (sur prescription), Sels de réhydratation orale', '2026-06-01 13:48:31');

